// 2.7.3 | 2022-05-05 | raj  | DFCT0010884 - All child/descendant tasks of an ORDERED TASK should be in "WAIT" state until the earlier order task has been completed
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// STRY0076605 - check to see if task is in wait state due to task order
	var TaskerHelper = new TaskerHelpers();
	current.state = TaskerHelper.getUpdatedState(current);

	// DFCT0010884
	if(current.state == -3){
		// if this task is paused by order by, pause all children of the task
		if(current.calchaschildren >0 && !TaskerHelper.isTaskOrderOfTaskActive(current)){
			TaskerHelper.pauseOrder(current);
		}
	} else if (previous.state == -3){
		if(current.calchaschildren > 0 && TaskerHelper.isTaskOrderOfTaskActive(current)){
			TaskerHelper.startOrder(current);
		}
	}

})(current, previous);
